mapper.select:
select count(1)
from purchase_order po
         inner join purchase_order_line pol on pol.order_id = po.id
where po.id = #{line.sourceOrderId}
  and po.order_code = #{line.sourceOrderCode}
  and pol.id = #{line.sourceOrderLineId}
  and pol.line_no = #{line.sourceOrderLineNo}
  and pol.material_id = #{line.materialId}
  and pol.material_code = #{line.materialCode}

select count(distinct ifnull(warehouse_code, ''))
from purchase_inbound_line
where inbound_id = #{inboundId}

select count(1)
from purchase_receipt r
         inner join purchase_receipt_line rl on rl.receipt_id = r.id
         inner join purchase_order po on po.id = rl.source_order_id
         inner join purchase_order_line pol on pol.id = rl.source_order_line_id
where r.id = #{line.sourceReceiptId}
  and r.receipt_code = #{line.sourceReceiptCode}
  and rl.id = #{line.sourceReceiptLineId}
  and rl.line_no = #{line.sourceReceiptLineNo}
  and po.id = #{line.sourceOrderId}
  and po.order_code = #{line.sourceOrderCode}
  and pol.id = #{line.sourceOrderLineId}
  and pol.line_no = #{line.sourceOrderLineNo}
  and rl.material_id = #{line.materialId}
  and rl.material_code = #{line.materialCode}

mapper.update:
update purchase_order_line pol
    inner join purchase_order po on po.id = pol.order_id
set pol.received_quantity = pol.received_quantity + #{quantity}
where pol.id = #{orderLineId}
  and po.status = 'APPROVED'
  and pol.received_quantity + #{quantity} <= pol.order_quantity

update purchase_order_line
set qualified_quantity = qualified_quantity + #{quantity}
where id = #{orderLineId}
  and qualified_quantity + #{quantity} >= 0
  and qualified_quantity + #{quantity} <= received_quantity

update purchase_order_line
set inbound_quantity = inbound_quantity + #{quantity}
where id = #{orderLineId}
  and inbound_quantity + #{quantity} >= 0
  and inbound_quantity + #{quantity} <= qualified_quantity

update purchase_receipt_line rl
    inner join purchase_receipt r on r.id = rl.receipt_id
set rl.inbound_quantity = rl.inbound_quantity + #{quantity}
where rl.id = #{receiptLineId}
  and r.status = 'APPROVED'
  and rl.pending_quantity = 0
  and rl.qualified_quantity - rl.inbound_quantity >= #{quantity}
  and rl.inbound_quantity + #{quantity} >= 0

update inventory_balance
set quantity           = quantity - #{transaction.quantity},
    available_quantity = available_quantity - #{transaction.quantity},
    last_update_time   = now(),
    update_by          = #{transaction.createBy},
    update_time        = now()
where material_id = #{transaction.materialId}
  and warehouse_code = #{transaction.warehouseCode}
  and location_code = #{transaction.locationCode}
  and lot_no = #{transaction.lotNo}
  and quantity >= #{transaction.quantity}
  and available_quantity >= #{transaction.quantity}
